# bash completion for magus
# Generated by `magus completion bash`. Source from your bashrc:
#   source <(magus completion bash)

_magus_complete() {
    local cur prev cmd
    COMPREPLY=()
    cur="${COMP_WORDS[COMP_CWORD]}"
    prev="${COMP_WORDS[COMP_CWORD-1]}"

    local subcommands="ls graph describe run x affected mage version help completion doctor"
    local verbs="ls build test lint format clean generate ci"
    local shells="bash zsh fish powershell"
    local affected_flags="--explain --plan --bisect --base --stdin --graph"

    if [[ "$COMP_CWORD" -eq 1 ]]; then
        COMPREPLY=( $(compgen -W "$subcommands" -- "$cur") )
        return 0
    fi

    cmd="${COMP_WORDS[1]}"

    case "$cmd" in
        run)
            if [[ "$COMP_CWORD" -eq 2 ]]; then
                COMPREPLY=( $(compgen -W "$verbs" -- "$cur") )
            else
                local projects
                projects=$(magus ls -o name 2>/dev/null)
                COMPREPLY=( $(compgen -W "$projects" -- "$cur") )
            fi
            ;;
        affected)
            if [[ "$cur" == -* ]]; then
                COMPREPLY=( $(compgen -W "$affected_flags" -- "$cur") )
            elif [[ "$COMP_CWORD" -eq 2 ]]; then
                COMPREPLY=( $(compgen -W "$verbs" -- "$cur") )
            fi
            ;;
        describe)
            local projects
            projects=$(magus ls -o name 2>/dev/null)
            COMPREPLY=( $(compgen -W "$projects" -- "$cur") )
            ;;
        x)
            local projects
            projects=$(magus ls -o name 2>/dev/null)
            COMPREPLY=( $(compgen -W "$projects" -- "$cur") )
            ;;
        completion)
            if [[ "$COMP_CWORD" -eq 2 ]]; then
                COMPREPLY=( $(compgen -W "$shells" -- "$cur") )
            fi
            ;;
        graph)
            COMPREPLY=( $(compgen -W "-upstream -lang -depth -root -o -output" -- "$cur") )
            ;;
    esac
    return 0
}
complete -F _magus_complete magus mgs
